module Merger_511 ( GLow, PLow, GHi, PHi, Gout, Pout );
  input GLow, PLow, GHi, PHi;
  output Gout, Pout;
  wire   n2;

  AND2_X1 U1 ( .A1(PLow), .A2(PHi), .ZN(Pout) );
  INV_X1 U2 ( .A(n2), .ZN(Gout) );
  AOI21_X1 U3 ( .B1(GLow), .B2(PHi), .A(GHi), .ZN(n2) );
endmodule


module LFRecursive_N2_511 ( Gen, Prop, blockGen, blockProp );
  input [1:0] Gen;
  input [1:0] Prop;
  output [1:0] blockGen;
  output [1:0] blockProp;
  wire   \Gen[0] , \Prop[0] ;
  assign blockGen[0] = \Gen[0] ;
  assign \Gen[0]  = Gen[0];
  assign blockProp[0] = \Prop[0] ;
  assign \Prop[0]  = Prop[0];

  Merger_511 merging2 ( .GLow(\Gen[0] ), .PLow(\Prop[0] ), .GHi(Gen[1]), .PHi(
        Prop[1]), .Gout(blockGen[1]), .Pout(blockProp[1]) );
endmodule


